const defaultListId = Number($env.LISTMONK_DEFAULT_LIST_ID || 1);

const rows = items.flatMap((item) => {
  const j = item.json || {};

  if (j.listmonk_sync_queue_id) return [j];
  if (Array.isArray(j.rows)) return j.rows;
  if (Array.isArray(j.result)) return j.result;
  if (Array.isArray(j.data)) return j.data;

  return [];
});

if (rows.length === 0) {
  return [];
}

return rows.map((row) => {
  const queueId = row.listmonk_sync_queue_id;

  if (!queueId) {
    throw new Error(
      'Queue row is missing listmonk_sync_queue_id. Input was: ' +
      JSON.stringify(row)
    );
  }

  const listId = Number(row.listmonk_list_id || defaultListId);
  if (!listId) throw new Error('LISTMONK_DEFAULT_LIST_ID is required');

  const details =
    typeof row.details === 'string'
      ? JSON.parse(row.details || '{}')
      : (row.details || {});

  const name =
    [details.first_name, details.last_name].filter(Boolean).join(' ') ||
    row.email_normalized;

  return {
    json: {
      ...row,
      details,
      queueId,
      listId,
      auth: `token ${$env.LISTMONK_API_USER}:${$env.LISTMONK_API_TOKEN}`,
      subscriberName: name
    }
  };
});

const preparedItems = $items('Code - Prepare Listmonk Request');

return items.map((item, itemIndex) => {
  const previous = preparedItems[itemIndex]?.json || {};
  const body = item.json.body || item.json;
  const statusCode = item.json.statusCode || body?.statusCode || null;
  const httpFailed = !!item.json.error || (statusCode !== null && Number(statusCode) >= 400);

  if (httpFailed) {
    return {
      json: {
        ...previous,
        body,
        error: item.json.error || body?.error || body?.message || 'Listmonk subscriber lookup failed',
        httpStatusCode: statusCode,
        httpFailed: true
      }
    };
  }

  const results =
    body?.data?.results ||
    body?.data ||
    body?.results ||
    [];

  const subscriber = Array.isArray(results) ? (results[0] || null) : null;

  return {
    json: {
      ...previous,
      body,
      httpStatusCode: statusCode,
      subscriber,
      subscriberFound: !!subscriber,
      httpFailed: false
    }
  };
});

