SELECT public.listmonk_mark_sync_success(
  NULLIF('{{ $json.queueId || $json.listmonk_sync_queue_id || "" }}', '')::uuid,
  NULLIF('{{ $json.body?.data?.id || $json.subscriber?.id || $json.id || "" }}', '')::integer,
  NULLIF('{{ $json.body?.data?.uuid || $json.subscriber?.uuid || $json.uuid || "" }}', '')::uuid,
  '{{ JSON.stringify($json.body || $json).replace(/'/g, "''") }}'::jsonb
);

SELECT public.listmonk_mark_sync_failure(
  NULLIF('{{ $json.queueId || $json.listmonk_sync_queue_id || "" }}', '')::uuid,
  {{ JSON.stringify($json.error?.message || $json.error || $json.message || 'Listmonk sync failed') }},
  '{{ JSON.stringify($json.body || $json).replace(/'/g, "''") }}'::jsonb
);

