const sourceItems = $items('Code - Merge Subscriber Lookup');

return items.map((item, itemIndex) => {
  const pairedIndex = item.pairedItem?.item ?? itemIndex;
  const previous =
    sourceItems[pairedIndex]?.json ||
    sourceItems[itemIndex]?.json ||
    sourceItems[0]?.json ||
    {};

  const body = item.json.body || item.json;
  const statusCode = item.json.statusCode || body?.statusCode || null;
  const httpFailed = !!item.json.error || (statusCode !== null && Number(statusCode) >= 400);

  return {
    json: {
      ...previous,
      body,
      httpStatusCode: statusCode,
      error: item.json.error || body?.error || body?.message || null,
      httpFailed,
      subscriber: body?.data?.id ? body.data : previous.subscriber || null
    }
  };
});

const sourceItems = $items('Code - Merge Subscriber Lookup');

return items.map((item, itemIndex) => {
  const pairedIndex = item.pairedItem?.item ?? itemIndex;
